import{_ as t,o as s,c as e,a3 as n}from"./chunks/framework.BveOjhN0.js";const u=JSON.parse('{"title":"权限模型","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/basic-app/permissions.md","filePath":"cosmos/basic-app/permissions.md","lastUpdated":1783216089000}'),o={name:"cosmos/basic-app/permissions.md"};function r(i,a,l,p,d,c){return s(),e("div",null,[...a[0]||(a[0]=[n(`<h1 id="权限模型" tabindex="-1">权限模型 <a class="header-anchor" href="#权限模型" aria-label="Permalink to &quot;权限模型&quot;">​</a></h1><p>XiHan.BasicApp 的权限体系融合了 <strong>RBAC（基于角色）</strong> 与 <strong>ABAC（基于属性）</strong>，并叠加数据范围、字段级脱敏与多租户隔离。这是系统最核心也最需要理解的部分。</p><h2 id="权限码" tabindex="-1">权限码 <a class="header-anchor" href="#权限码" aria-label="Permalink to &quot;权限码&quot;">​</a></h2><p>权限的基本单位是<strong>权限码</strong>，格式为三段：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>resource : action : scope</span></span>
<span class="line"><span>资源       动作      范围</span></span></code></pre></div><ul><li>例：<code>user:read:dept</code>（读取本部门用户）、<code>order:export:self</code>（导出本人订单）</li><li>超级管理员使用通配 <code>*:*:*</code>，放行一切</li></ul><p>前端页面、字段、操作三级都按权限码过滤：没有对应权限码，元素不渲染 / 不可操作。</p><h2 id="rbac-角色驱动" tabindex="-1">RBAC：角色驱动 <a class="header-anchor" href="#rbac-角色驱动" aria-label="Permalink to &quot;RBAC：角色驱动&quot;">​</a></h2><ul><li>用户通过<strong>角色</strong>获得权限码集合</li><li>角色支持<strong>层级继承</strong>（用闭包表存储层级关系），子角色继承父角色权限</li><li><strong>会话角色激活</strong>：登录后可在一次会话内激活/切换生效角色，实现动态职责分离（同一用户不同时刻以不同角色办事）</li></ul><h2 id="数据范围-data-scope" tabindex="-1">数据范围（Data Scope） <a class="header-anchor" href="#数据范围-data-scope" aria-label="Permalink to &quot;数据范围（Data Scope）&quot;">​</a></h2><p>同一个权限码，能看到的数据行随<strong>数据范围</strong>收窄：</p><table tabindex="0"><thead><tr><th>范围</th><th>含义</th></tr></thead><tbody><tr><td>本人（self）</td><td>只能操作自己的数据</td></tr><tr><td>部门（dept）</td><td>可操作本部门（含子部门）数据</td></tr><tr><td>租户（tenant）</td><td>可操作本租户全部数据</td></tr></tbody></table><p>数据范围在查询层生效，与权限码组合决定&quot;能对哪些行做这个动作&quot;。</p><h2 id="字段级脱敏-fls" tabindex="-1">字段级脱敏（FLS） <a class="header-anchor" href="#字段级脱敏-fls" aria-label="Permalink to &quot;字段级脱敏（FLS）&quot;">​</a></h2><p>即使有权读取某条记录，<strong>敏感字段</strong>也可能被脱敏（如手机号、证件号打码）。脱敏由字段级权限门控：可读且未脱敏才显示原值，否则显示掩码。列表页的导出与显示保持一致的脱敏策略。</p><h2 id="abac-属性驱动的约束" tabindex="-1">ABAC：属性驱动的约束 <a class="header-anchor" href="#abac-属性驱动的约束" aria-label="Permalink to &quot;ABAC：属性驱动的约束&quot;">​</a></h2><p>在 RBAC 之上，ABAC 用<strong>属性与规则</strong>做更细的运行时约束：</p><ul><li><strong>约束规则</strong>：时间窗（仅工作时间可操作）、IP（仅内网可访问）、表达式（自定义条件）</li><li>评估时综合主体属性（用户）、资源属性、环境属性，返回是否放行</li></ul><blockquote><p>框架侧的授权采用<strong>实时校验</strong>而非信任令牌里的冻结声明——权限的授予/回收、用户禁用、会话失效都会立即生效。</p></blockquote><h2 id="权限申请与审批" tabindex="-1">权限申请与审批 <a class="header-anchor" href="#权限申请与审批" aria-label="Permalink to &quot;权限申请与审批&quot;">​</a></h2><ul><li>用户可发起<strong>权限申请</strong>，走审批流程</li><li>权限的每次变更<strong>留痕</strong>（谁、何时、授予/回收了什么），便于审计追溯</li></ul><h2 id="多租户隔离" tabindex="-1">多租户隔离 <a class="header-anchor" href="#多租户隔离" aria-label="Permalink to &quot;多租户隔离&quot;">​</a></h2><ul><li><strong>字段级隔离</strong>：数据按 <code>TenantId</code> 隔离，全局数据使用 <code>TenantId=0</code> 约定</li><li><strong>邮箱全局唯一登录</strong>：登录后按用户归属自动落点（平台控制台 / 租户工作台 / 租户选择页），可随时切换租户</li><li><strong>超级管理员平台态运维</strong>：可切入任意租户代为管理</li><li><strong>租户版本（Edition）门控</strong>：不同版本对应不同的权限白名单，运行时门控；开通版本时一站式创建管理员、角色与授权；<strong>降级时自动回收越权授权</strong></li></ul><h2 id="组合起来" tabindex="-1">组合起来 <a class="header-anchor" href="#组合起来" aria-label="Permalink to &quot;组合起来&quot;">​</a></h2><p>一次访问的判定链大致是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请求进来</span></span>
<span class="line"><span>  → 认证：你是谁（JWT 解析出用户/租户/会话）</span></span>
<span class="line"><span>  → 租户解析：落到哪个租户上下文</span></span>
<span class="line"><span>  → 授权(RBAC)：有没有这个权限码</span></span>
<span class="line"><span>  → 授权(ABAC)：属性约束是否满足（时间/IP/表达式）</span></span>
<span class="line"><span>  → 数据范围：能看到哪些行</span></span>
<span class="line"><span>  → 字段脱敏：敏感字段是否显示原值</span></span></code></pre></div><p>每一层都可能把访问收窄或拒绝，层层收紧，默认从严。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./architecture">系统架构</a>：权限判定在请求管道中的位置</li><li><a href="./../framework/packages/authorization">框架 · 授权模块</a>：底层 RBAC / ABAC 实现</li><li><a href="./../framework/packages/authentication">框架 · 认证模块</a>：JWT / OAuth2 / 2FA 实现</li></ul>`,29)])])}const g=t(o,[["render",r]]);export{u as __pageData,g as default};
